// Build the Calendly API URL for listing events from the past 3 months
const userUri = $json.resource?.uri || $json.uri || '';
const orgUri = $json.resource?.current_organization || '';

// Calculate date range: 3 months ago to now
const now = new Date();
const threeMonthsAgo = new Date(now);
threeMonthsAgo.setMonth(threeMonthsAgo.getMonth() - 3);

return [{
  json: {
    user_uri: userUri,
    organization_uri: orgUri,
    min_start_time: threeMonthsAgo.toISOString(),
    max_start_time: now.toISOString(),
    all_events: [],
    next_page_token: '',
    page_count: 0
  }
}];

// Flatten the events collection into individual items for processing
const events = $json.collection || [];
const results = events.map(event => ({
  json: {
    event_uri: event.uri || '',
    event_uuid: (event.uri || '').split('/').pop(),
    event_name: event.name || 'Meeting',
    start_time: event.start_time || '',
    end_time: event.end_time || '',
    status: event.status || '',
    event_type: event.event_type || '',
    meeting_category: (() => {
      const name = (event.name || '').toLowerCase();
      if (name.includes('discovery') || name.includes('intro')) return 'Discovery';
      if (name.includes('audit') || name.includes('rapid')) return 'Audit';
      if (name.includes('onboarding') || name.includes('kickoff')) return 'Onboarding';
      if (name.includes('check-in') || name.includes('weekly') || name.includes('review')) return 'Check-In';
      return 'Other';
    })()
  }
}));

return results.length > 0 ? results : [{ json: { _empty: true } }];

// Extract the first invitee (your client) from the Calendly invitees list
const invitees = $json.collection || [];
const invitee = invitees[0] || {};
const eventData = $('Loop Events').first().json;

return [{
  json: {
    invitee_name: invitee.name || '',
    invitee_email: invitee.email || '',
    event_name: eventData.event_name || 'Meeting',
    event_uuid: eventData.event_uuid || '',
    start_time: eventData.start_time || '',
    end_time: eventData.end_time || '',
    meeting_category: eventData.meeting_category || 'Other',
    event_status: eventData.status || '',
    questions_and_answers: invitee.questions_and_answers || []
  }
}];

// Determine the correct status update based on meeting category and timing
const STATUS_PRIORITY = {
  'Connection Sent': 1,
  'Connection Accepted': 2,
  'Loom Sent': 3,
  'Follow-Up Sequence': 4,
  'Responded': 5,
  'Pending Approval': 6,
  'Meeting Booked': 7,
  'Meeting Held': 8,
  'Proposal Sent': 9,
  'Contract Sent': 10,
  'Project Started': 11,
  'Declined': 0
};

const contact = $('Find Notion Contact').first().json.results[0];
const contactId = contact.id;
const currentStatus = contact?.properties?.Status?.select?.name || '';
const currentPriority = STATUS_PRIORITY[currentStatus] || 0;

const eventData = $('Extract Invitee Data').first().json;
const startTime = new Date(eventData.start_time);
const now = new Date();
const meetingHappened = startTime < now;

// Determine new status
let newStatus;
if (meetingHappened) {
  newStatus = 'Meeting Held';
} else {
  newStatus = 'Meeting Booked';
}

const newPriority = STATUS_PRIORITY[newStatus] || 0;
const shouldUpdateStatus = newPriority > currentPriority;

return [{
  json: {
    contact_id: contactId,
    current_status: currentStatus,
    new_status: shouldUpdateStatus ? newStatus : null,
    should_update_status: shouldUpdateStatus,
    meeting_happened: meetingHappened,
    invitee_name: eventData.invitee_name,
    invitee_email: eventData.invitee_email,
    event_name: eventData.event_name,
    start_time: eventData.start_time,
    meeting_category: eventData.meeting_category
  }
}];

